// Validate and map the incoming order payload.
// Expected input:
//   { symbol, side, qty, order_type, limit_price?, stop_price?,
//     strategy_id?, user_id?, trading_mode? }
const body = $input.item.json.body || $input.item.json;

if (!body.symbol) throw new Error('Missing required field: symbol');
if (!body.side) throw new Error('Missing required field: side (BUY|SELL)');
if (!body.qty || body.qty <= 0) throw new Error('Missing or invalid field: qty');

const validSides = ['BUY', 'SELL', 'buy', 'sell'];
if (!validSides.includes(body.side)) throw new Error('side must be BUY or SELL');

const payload = {
  symbol: body.symbol.toUpperCase(),
  side: body.side.toUpperCase(),
  order_type: (body.order_type || body.type || 'MARKET').toUpperCase(),
  qty: Number(body.qty),
  limit_price: body.limit_price ? Number(body.limit_price) : undefined,
  stop_price: body.stop_price ? Number(body.stop_price) : undefined,
  strategy_id: body.strategy_id || '',
  user_id: body.user_id || '',
  trading_mode: (body.trading_mode || 'PAPER').toUpperCase(),
};

// Remove undefined fields
Object.keys(payload).forEach(k => payload[k] === undefined && delete payload[k]);

return { json: payload };
